  ('dietitian-moex-01805', 'dietitian', 'dietitian-moex-108-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關抗生素對抑制細菌轉譯作用之敘述，下列何者正確？', '["四環黴素（tetracyclin）可與細菌23S RNA結合，進而抑制轉譯作用", "紅黴素（erythromycin）可抑制細菌延伸過程（elongation），進而抑制轉譯作用", "鏈黴素（streptomycin）為核糖體肽基轉移酶（peptidyltransferase）抑制物，進而抑制轉譯作用", "嘌呤黴素（puromycin）可直接抑制已攜帶胺基酸之tRNA與核糖體結合，進而抑制轉譯作用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "ce2dbd3ab2da", "answer_pdf_sha1": "00f73a9082c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
